// Content approved - publish
const items = $input.all();
return items.map(item => ({
  json: {
    status: 'published',
    content: item.json.ai_enhanced_content || 'Approved content',
    published_at: new Date().toISOString()
  }
}));

// Content rejected - route back for revision
const items = $input.all();
return items.map(item => ({
  json: {
    status: 'rejected',
    content: item.json.original_content || 'Rejected',
    rejected_at: new Date().toISOString(),
    action: 'Send back to content team for revision'
  }
}));

